      switch (status) {
        case 'success': return <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-bold border border-green-200">Thành công</span>;
        case 'failed': return <span className="bg-red-100 text-red-700 px-3 py-1 rounded-full text-xs font-bold border border-red-200">Thất bại</span>;
        case 'draft': return <span className="bg-slate-100 text-slate-700 px-3 py-1 rounded-full text-xs font-bold border border-slate-200">Lưu nháp</span>;
        case 'partial': return <span className="bg-orange-100 text-orange-700 px-3 py-1 rounded-full text-xs font-bold border border-orange-200">Thành công một phần</span>;
        case 'processing': return <span className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold border border-blue-100">Đang xử lý</span>;
        default: return null;
      }
    };

    const filteredListings = MOCK_LISTINGS.filter(l => listingFilter === 'all' || l.status === listingFilter);

    return (
      <div className="space-y-4 animate-fade-in h-full flex flex-col">
        {/* Header */}
        <div className="flex justify-between items-center bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
           <div>
              <h3 className="font-bold text-lg text-slate-800">Danh sách sản phẩm đăng bán</h3>
              <p className="text-sm text-slate-500">Quản lý và đăng tải sản phẩm lên các sàn TMĐT.</p>
           </div>
           <button 
             onClick={() => setIsListingModalOpen(true)}
             className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold text-sm flex items-center gap-2 shadow-sm transition-colors"
           >
             <UploadCloud size={18} /> Đăng bán sản phẩm mới
           </button>
        </div>

        {/* Filter Tabs */}
        <div className="bg-white border-b border-slate-200 rounded-t-xl overflow-x-auto">
           <div className="flex w-max">
              {filters.map(filter => (
                <button
                  key={filter.id}
                  onClick={() => setListingFilter(filter.id)}
                  className={`px-5 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${listingFilter === filter.id ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                >
                  {filter.label}
                </button>
              ))}
           </div>
        </div>

        {/* Toolbar */}
        <div className="bg-white p-4 border border-t-0 border-slate-200 shadow-sm flex flex-col sm:flex-row gap-4 items-center">
           <div className="relative flex-1 w-full">
              <input 
                type="text" 
                placeholder="Tìm kiếm sản phẩm đăng bán..." 
                className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
           </div>
           <div className="flex gap-2 w-full sm:w-auto">
              <button className="px-4 py-2 border border-slate-200 rounded-lg text-slate-600 text-sm hover:bg-slate-50 flex items-center gap-2">
                 <Filter size={16} /> Lọc sản phẩm
              </button>
           </div>
        </div>

        {/* Data Table */}
        <div className="flex-1 bg-white border border-slate-200 rounded-b-xl shadow-sm overflow-hidden flex flex-col">
           <div className="overflow-auto flex-1">
              <table className="w-full text-sm text-left">
                 <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200">
                    <tr>
                       <th className="px-6 py-4 w-12 text-center"><input type="checkbox" className="rounded" /></th>
                       <th className="px-6 py-4">Danh sách sản phẩm</th>
                       <th className="px-6 py-4">Thời gian tạo/sửa</th>
                       <th className="px-6 py-4">Trạng thái</th>
                       <th className="px-6 py-4">Sàn đăng bán</th>
                       <th className="px-6 py-4 text-center">Thao tác</th>
                    </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                    {filteredListings.map(item => (
                       <tr key={item.id} className="hover:bg-slate-50 group">
                          <td className="px-6 py-4 text-center"><input type="checkbox" className="rounded" /></td>
                          <td className="px-6 py-4">
                             <div className="flex items-center gap-3">
                                <img src={item.image} alt="" className="w-12 h-12 rounded object-cover border border-slate-200 bg-white" />
                                <span className="font-medium text-blue-600 hover:underline cursor-pointer line-clamp-2 max-w-md">{item.productName}</span>
                             </div>
                          </td>
                          <td className="px-6 py-4 text-slate-500">{item.updatedAt}</td>
                          <td className="px-6 py-4">{getStatusBadge(item.status)}</td>
                          <td className="px-6 py-4">
                             {item.platforms.length > 0 ? (
                                <div className="flex items-center gap-2">
                                   {item.platforms.length > 1 ? (
                                      <div className="flex items-center gap-1 text-slate-600 font-medium">
                                         <Store size={16} className="text-blue-500" /> Đa sàn
                                      </div>
                                   ) : (
                                      <div className="flex items-center gap-2">
                                         {item.platforms.map(p => (
                                            <div key={p} className="flex items-center gap-1 bg-slate-50 px-2 py-1 rounded border border-slate-100">
                                               {LOGOS[p] && <img src={LOGOS[p]} className="w-4 h-4 object-contain" />}
                                               <span>{p}</span>
                                            </div>
                                         ))}
                                      </div>
                                   )}
                                </div>
                             ) : <span className="text-slate-400">-</span>}
                          </td>
                          <td className="px-6 py-4 text-center">
                             <button className="text-slate-400 hover:text-blue-600 p-2"><Edit3 size={18} /></button>
                          </td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      </div>
    );
  };

  const renderListingWizard = () => {
    if (!isListingModalOpen) return null;

    return (
      <div className="fixed inset-0 z-[60] bg-black/50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
         <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl h-[85vh] flex flex-col overflow-hidden">
            {/* Wizard Header */}
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
               <div>
                  <h3 className="font-bold text-lg text-slate-800">Đăng bán sản phẩm mới</h3>
                  <p className="text-xs text-slate-500">Bước {listingStep}/4: {listingStep === 1 ? 'Chọn nguồn dữ liệu' : listingStep === 2 ? 'Chọn gian hàng đích' : listingStep === 3 ? 'Chọn sản phẩm' : 'Chỉnh sửa & Đăng'}</p>
               </div>
               <button onClick={resetListingWizard} className="text-slate-400 hover:text-slate-600"><XCircle size={24}/></button>
            </div>

            {/* Wizard Content */}
            <div className="flex-1 overflow-y-auto p-6 bg-slate-50/50">
               {listingStep === 1 && (
                  <div className="space-y-4">
                     <h4 className="font-bold text-slate-700 mb-4 text-center">Bạn muốn lấy dữ liệu sản phẩm từ đâu?</h4>
                     <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div 
                           onClick={() => { setListingSource('system'); setListingStep(2); }}
                           className="bg-white p-6 rounded-xl border-2 border-slate-200 hover:border-blue-500 cursor-pointer flex flex-col items-center gap-4 transition-all hover:shadow-lg group"
                        >
                           <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center text-blue-600 group-hover:bg-blue-100">
                              <Box size={32} />
                           </div>
                           <div className="text-center">
                              <h5 className="font-bold text-slate-800">Sản phẩm gian hàng</h5>
                              <p className="text-xs text-slate-500 mt-1">Lấy từ danh sách sản phẩm có sẵn trên OmniSales</p>
                           </div>
                        </div>
                        <div 
                           onClick={() => { setListingSource('shop'); setListingStep(2); }}
                           className="bg-white p-6 rounded-xl border-2 border-slate-200 hover:border-green-500 cursor-pointer flex flex-col items-center gap-4 transition-all hover:shadow-lg group"
                        >
                           <div className="w-16 h-16 bg-green-50 rounded-full flex items-center justify-center text-green-600 group-hover:bg-green-100">
                              <Store size={32} />
                           </div>
                           <div className="text-center">
                              <h5 className="font-bold text-slate-800">Lấy dữ liệu từ Sapo/KiotViet</h5>
                              <p className="text-xs text-slate-500 mt-1">Đồng bộ từ phần mềm quản lý khác</p>
                           </div>
                        </div>
                        <div 
                           onClick={() => { setListingSource('link'); setListingStep(2); }}
                           className="bg-white p-6 rounded-xl border-2 border-slate-200 hover:border-orange-500 cursor-pointer flex flex-col items-center gap-4 transition-all hover:shadow-lg group"
                        >
                           <div className="w-16 h-16 bg-orange-50 rounded-full flex items-center justify-center text-orange-600 group-hover:bg-orange-100">
                              <LinkIcon size={32} />
                           </div>
                           <div className="text-center">
                              <h5 className="font-bold text-slate-800">Nhập link sản phẩm</h5>
                              <p className="text-xs text-slate-500 mt-1">Sao chép link từ Shopee, Lazada, Tiki...</p>
                           </div>
                        </div>
                     </div>
                  </div>
               )}

               {listingStep === 2 && (
                  <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm max-w-2xl mx-auto">
                     <h4 className="font-bold text-slate-800 mb-4">Chọn gian hàng đăng bán</h4>
                     <div className="space-y-4">
                        {INITIAL_INTEGRATIONS.map((integration, idx) => (
                           <div key={idx}>
                              <div className="flex items-center gap-2 mb-2 font-medium text-slate-700 bg-slate-50 p-2 rounded">
                                 {LOGOS[integration.platform] && <img src={LOGOS[integration.platform]} className="w-5 h-5 object-contain" />}
                                 {integration.platform}
                              </div>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 pl-2">
                                 {integration.shops.map(shop => (
                                    <div 
                                       key={shop.id}
                                       onClick={() => toggleListingShop(shop.id)}
                                       className={`p-3 border rounded-lg cursor-pointer flex items-center gap-3 transition-colors ${listingSelectedShops.includes(shop.id) ? 'border-blue-500 bg-blue-50' : 'border-slate-200 hover:border-blue-300'}`}
                                    >
                                       <div className={`w-5 h-5 rounded border flex items-center justify-center ${listingSelectedShops.includes(shop.id) ? 'bg-blue-500 border-blue-500' : 'bg-white border-slate-300'}`}>
                                          {listingSelectedShops.includes(shop.id) && <CheckSquare size={14} className="text-white" />}
                                       </div>
                                       <span className="text-sm text-slate-700">{shop.name}</span>
                                    </div>
                                 ))}
                              </div>
                           </div>
                        ))}
                     </div>
                  </div>
               )}

               {listingStep === 3 && (
                  <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                     <h4 className="font-bold text-slate-800 mb-4">Chọn sản phẩm từ hệ thống</h4>
                     <div className="mb-4 relative">
                        <input 
                           type="text" 
                           placeholder="Tìm kiếm sản phẩm..." 
                           className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                        />
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                     </div>
                     <div className="max-h-[400px] overflow-y-auto border border-slate-200 rounded-lg">
