                              className={`p-3 border-b border-slate-100 flex items-center gap-4 cursor-pointer hover:bg-slate-50 ${listingSelectedProducts.includes(product.id) ? 'bg-blue-50/50' : ''}`}
                           >
                              <div className={`w-5 h-5 shrink-0 rounded border flex items-center justify-center ${listingSelectedProducts.includes(product.id) ? 'bg-blue-500 border-blue-500' : 'bg-white border-slate-300'}`}>
                                 {listingSelectedProducts.includes(product.id) && <CheckSquare size={14} className="text-white" />}
                              </div>
                              <img src={product.image} className="w-12 h-12 rounded object-cover border border-slate-200" />
                              <div className="flex-1 min-w-0">
                                 <div className="font-medium text-slate-800 truncate">{product.name}</div>
                                 <div className="text-xs text-slate-500">SKU: {product.sku} | Tồn: {product.stock}</div>
                              </div>
                              <div className="font-bold text-slate-700">{formatCurrency(product.price)}</div>
                           </div>
