       <div className="bg-gradient-to-r from-blue-600 to-indigo-600 rounded-xl p-6 text-white shadow-lg">
          <h3 className="text-lg font-bold flex items-center gap-2">
             <ArrowRightLeft className="text-blue-200" /> Đồng bộ sản phẩm giữa các Shop
          </h3>
          <p className="text-blue-100 text-sm mt-1">
             Sao chép tồn kho, giá bán hoặc thông tin sản phẩm từ một shop nguồn sang nhiều shop khác (Cross-Platform).
          </p>
       </div>

       <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Source & Config */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6 space-y-6">
             <div>
                <label className="block text-sm font-bold text-slate-800 mb-2">1. Chọn Shop Nguồn (Gốc)</label>
                <select 
                  value={syncConfig.sourceShopId}
                  onChange={(e) => setSyncConfig({...syncConfig, sourceShopId: e.target.value, targetShopIds: []})}
                  className="w-full border-slate-200 rounded-lg px-3 py-2.5 text-sm focus:ring-indigo-500 focus:border-indigo-500 bg-slate-50"
                >
                   <option value="">-- Chọn shop nguồn --</option>
                   {allShops.map(shop => (
                      <option key={shop.id} value={shop.id}>[{shop.platform}] {shop.name}</option>
                   ))}
                </select>
             </div>

             <div>
                <label className="block text-sm font-bold text-slate-800 mb-2">3. Cấu hình đồng bộ</label>
                <div className="space-y-3 bg-slate-50 p-4 rounded-lg border border-slate-200">
                  <label className="flex items-center gap-3 cursor-pointer">
                     <input 
                        type="checkbox" 
                        checked={syncConfig.syncStock} 
                        onChange={() => setSyncConfig({...syncConfig, syncStock: !syncConfig.syncStock})}
                        className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500" 
                     />
                     <div>
                        <div className="text-sm font-medium text-slate-700">Đồng bộ Tồn kho</div>
                        <div className="text-xs text-slate-500">Tồn kho shop nguồn sẽ ghi đè shop đích</div>
                     </div>
                  </label>
                  <label className="flex items-center gap-3 cursor-pointer">
                     <input 
                        type="checkbox" 
                        checked={syncConfig.syncPrice} 
                        onChange={() => setSyncConfig({...syncConfig, syncPrice: !syncConfig.syncPrice})}
                        className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500" 
                     />
                     <div>
                        <div className="text-sm font-medium text-slate-700">Đồng bộ Giá bán</div>
                        <div className="text-xs text-slate-500">Cập nhật giá bán lẻ (không bao gồm giá KM)</div>
                     </div>
                  </label>
                  <label className="flex items-center gap-3 cursor-pointer">
                     <input 
                        type="checkbox" 
                        checked={syncConfig.syncInfo} 
                        onChange={() => setSyncConfig({...syncConfig, syncInfo: !syncConfig.syncInfo})}
                        className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500" 
                     />
                     <div>
                        <div className="text-sm font-medium text-slate-700">Đồng bộ Thông tin (Tên, Mô tả, Ảnh)</div>
                        <div className="text-xs text-slate-500">Chỉ áp dụng khi sản phẩm đã liên kết SKU</div>
                     </div>
                  </label>
                </div>
             </div>

             <button 
                onClick={handleShopSync}
                disabled={isSyncing}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white py-3 rounded-lg font-bold shadow-md shadow-indigo-200 transition-all flex justify-center items-center gap-2"
             >
                <RefreshCw size={20} className={isSyncing ? "animate-spin" : ""} />
                {isSyncing ? 'Đang xử lý...' : 'Bắt đầu đồng bộ'}
             </button>
          </div>

          {/* Destination Shops */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6 flex flex-col">
             <div className="flex justify-between items-center mb-4">
                <label className="block text-sm font-bold text-slate-800">2. Chọn Shop Đích (Nhận dữ liệu)</label>
                <span className="text-xs font-bold bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full">
                   Đã chọn: {syncConfig.targetShopIds.length}
                </span>
             </div>

             <div className="flex-1 overflow-y-auto border border-slate-200 rounded-lg max-h-[400px]">
                {syncConfig.sourceShopId ? (
                   <div className="divide-y divide-slate-100">
                      {allShops.filter(s => s.id !== syncConfig.sourceShopId).map(shop => {
                         const isSelected = syncConfig.targetShopIds.includes(shop.id);
                         return (
                            <div 
                              key={shop.id} 
                              onClick={() => toggleTargetShop(shop.id)}
                              className={`p-3 flex items-center gap-3 cursor-pointer hover:bg-slate-50 transition-colors ${isSelected ? 'bg-indigo-50' : ''}`}
                            >
                               {isSelected ? (
                                  <CheckSquare className="text-indigo-600 shrink-0" size={20} />
                               ) : (
                                  <Square className="text-slate-300 shrink-0" size={20} />
                               )}
                               <div className="flex items-center gap-3 overflow-hidden">
                                  <div className="w-8 h-8 rounded border border-slate-200 bg-white flex items-center justify-center shrink-0 text-xs font-bold text-slate-500">
                                    {shop.platform[0]}
                                  </div>
                                  <div className="min-w-0">
                                     <div className="text-sm font-medium text-slate-700 truncate">{shop.name}</div>
                                     <div className="text-xs text-slate-400">{shop.platform}</div>
                                  </div>
                               </div>
                            </div>
                         );
                      })}
                   </div>
                ) : (
                   <div className="h-full flex flex-col items-center justify-center text-slate-400 p-8 text-center">
                      <Store size={40} className="mb-2 opacity-50" />
                      <p className="text-sm">Vui lòng chọn Shop nguồn trước</p>
                   </div>
                )}
             </div>
          </div>
       </div>
    </div>
  );

  const renderProductImport = () => (
    <div className="space-y-6 animate-fade-in">
       <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6">
          <div className="mb-6">
             <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <Download className="text-indigo-600" /> Khởi tạo sản phẩm từ Sàn
             </h3>
             <p className="text-sm text-slate-500 mt-1">
                Kéo toàn bộ thông tin sản phẩm từ Shopee/Lazada/TikTok về phần mềm để quản lý tập trung.
             </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
             <div className="space-y-4">
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Chọn Sàn nguồn</label>
                   <select className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500">
                      <option value="shopee">Shopee - Shop Mẹ & Bé Official</option>
                      <option value="lazada">Lazada - Tech World</option>
                      <option value="tiktok">TikTok - KOC Review</option>
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Tuỳ chọn</label>
                   <div className="flex flex-col gap-2">
                      <label className="flex items-center gap-2 text-sm text-slate-600 cursor-pointer">
                         <input type="checkbox" className="rounded text-indigo-600" defaultChecked /> Bỏ qua sản phẩm trùng SKU
                      </label>
                      <label className="flex items-center gap-2 text-sm text-slate-600 cursor-pointer">
                         <input type="checkbox" className="rounded text-indigo-600" defaultChecked /> Tải cả hình ảnh (có thể lâu hơn)
                      </label>
                   </div>
                </div>

                <button 
                   onClick={handleImportProducts}
                   disabled={isImporting}
                   className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-lg font-medium shadow-sm transition-all flex items-center gap-2 w-fit"
                >
                   {isImporting ? <LoaderBar /> : <Download size={18} />}
                   {isImporting ? 'Đang tải dữ liệu...' : 'Bắt đầu sao chép'}
                </button>
             </div>

             <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                <h4 className="font-bold text-slate-700 mb-3 text-sm">Hướng dẫn nhanh</h4>
                <ul className="space-y-2 text-sm text-slate-600 list-disc pl-4">
                   <li>Chọn gian hàng bạn muốn sao chép dữ liệu.</li>
                   <li>Hệ thống sẽ tự động tạo sản phẩm mới trong OmniSales.</li>
                   <li>Các thông tin được sao chép: Tên, Giá, SKU, Tồn kho, Mô tả, Hình ảnh.</li>
                   <li>Sau khi sao chép, bạn có thể liên kết tồn kho với các sàn khác.</li>
                </ul>

                {isImporting && (
                  <div className="mt-6">
                     <div className="flex justify-between text-xs font-bold text-indigo-600 mb-1">
                        <span>Tiến trình</span>
                        <span>{importProgress}%</span>
                     </div>
                     <div className="w-full bg-slate-200 rounded-full h-2">
                        <div className="bg-indigo-600 h-2 rounded-full transition-all duration-300" style={{ width: `${importProgress}%` }}></div>
                     </div>
                  </div>
                )}
             </div>
          </div>
       </div>
    </div>
  );

  const renderBulkEdit = () => (
    <div className="space-y-6 animate-fade-in">
       <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
         <h3 className="font-bold text-slate-800 mb-4">Công cụ sửa giá hàng loạt</h3>
         <div className="flex flex-col md:flex-row gap-4 items-end pb-6 border-b border-slate-100">
            <div className="flex-1">
               <label className="block text-sm font-medium text-slate-700 mb-1">Chọn danh mục</label>
               <select className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm">
                 <option>Tất cả sản phẩm</option>
                 <option>Thời trang nữ</option>
                 <option>Điện tử</option>
               </select>
            </div>
            <div className="flex-1">
               <label className="block text-sm font-medium text-slate-700 mb-1">Thao tác</label>
               <select className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm">
                 <option value="increase">Tăng giá theo %</option>
                 <option value="decrease">Giảm giá theo %</option>
                 <option value="set">Thiết lập giá cố định</option>
               </select>
            </div>
            <div className="w-32">
               <label className="block text-sm font-medium text-slate-700 mb-1">Giá trị (%)</label>
               <input 
                  type="number" 
                  value={bulkEditPercent}
                  onChange={(e) => setBulkEditPercent(Number(e.target.value))}
                  className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm"
                />
            </div>
            <button className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-medium shadow-sm hover:bg-indigo-700 transition-colors">
              Xem trước
            </button>
         </div>

         <div className="mt-6">
            <h4 className="font-bold text-slate-700 mb-3 text-sm">Sản phẩm sẽ được áp dụng (Xem trước 5 sản phẩm)</h4>
            <div className="overflow-x-auto">
               <table className="w-full text-sm">
                 <thead className="bg-slate-50 text-slate-500 font-semibold">
                   <tr>
                     <th className="px-4 py-3 text-left">Sản phẩm</th>
                     <th className="px-4 py-3 text-right">Giá hiện tại</th>
                     <th className="px-4 py-3 text-right">Giá mới (Dự kiến)</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                    {MOCK_PRODUCTS.slice(0, 5).map(p => (
                      <tr key={p.id}>
                        <td className="px-4 py-3">{p.name}</td>
                        <td className="px-4 py-3 text-right text-slate-600">{formatCurrency(p.price)}</td>
                        <td className="px-4 py-3 text-right font-bold text-indigo-600">
                          {formatCurrency(p.price * (1 + bulkEditPercent / 100))}
                        </td>
                      </tr>
                    ))}
                 </tbody>
               </table>
            </div>
            <div className="mt-6 flex justify-end">
               <button className="bg-slate-900 text-white px-6 py-2 rounded-lg font-medium shadow-lg shadow-indigo-200 hover:bg-slate-800 transition-colors" onClick={() => alert("Đã cập nhật giá thành công!")}>
                 Áp dụng thay đổi
               </button>
            </div>
         </div>
       </div>
    </div>
  );

  const LoaderBar = () => (
     <div className="flex gap-1">
        <span className="w-1.5 h-1.5 bg-white rounded-full animate-bounce"></span>
        <span className="w-1.5 h-1.5 bg-white rounded-full animate-bounce [animation-delay:-.3s]"></span>
        <span className="w-1.5 h-1.5 bg-white rounded-full animate-bounce [animation-delay:-.5s]"></span>
     </div>
  );

  return (
    <div className="pb-10">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Công cụ quản lý</h2>
        <p className="text-sm text-slate-500">Đồng bộ và quản lý dữ liệu sản phẩm trên diện rộng.</p>
      </div>

      {/* Navigation Tabs (Top) */}
      <div className="flex overflow-x-auto no-scrollbar gap-2 mb-6 bg-white p-2 rounded-xl border border-slate-100 shadow-sm">
        {tabs.map(tab => {
          const Icon = tab.icon;
          const isActive = activeTab === tab.id;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                isActive 
                  ? 'bg-indigo-600 text-white shadow-md' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <Icon size={18} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Content Area */}
      <div>
         {activeTab === 'listing' && renderListingTool()}
         {activeTab === 'sync' && renderShopSync()}
         {activeTab === 'import' && renderProductImport()}
         {activeTab === 'bulkedit' && renderBulkEdit()}
      </div>

      {/* Listing Wizard Modal */}
      {renderListingWizard()}
    </div>
  );
};

export default Tools;
